sqlite_int64 sqlite3_last_insert_rowid(sqlite3 *db){
  if( !sqlite3SafetyCheckOk(db) ){
    (void)sqlite3MisuseError(185987);
    return 0;
  }
  return db->lastRowid;
}

static void logBadConnection(const char *zType){
  sqlite3_log(21,
     "API call with %s database connection pointer",
     zType
  );
}
